-- Dumping structure for procedure havmor.generate_dim_date
DELIMITER //
CREATE PROCEDURE `generate_dim_date`(
    IN start_date DATE,
    IN end_date DATE
)
BEGIN
    SET @current := start_date;
    SET @end := end_date;

    WHILE @current <= @end DO
            date_key, full_date, date_name, date_name_us, date_name_eu,
            day_of_week, day_name_of_week, day_of_month, day_of_year, weekday_weekend,
            week_of_year, month_name, month_of_year, is_last_day_of_month,
            calendar_quarter, calendar_year, calendar_year_month, calendar_year_qtr,
            fiscal_month_of_year, fiscal_quarter, fiscal_year, fiscal_year_month, fiscal_year_qtr
        )
        VALUES (
            DATE_FORMAT(@current, '%Y%m%d'),
            @current,
            DATE_FORMAT(@current, '%Y/%m/%d'),
            DATE_FORMAT(@current, '%m/%d/%Y'),
            DATE_FORMAT(@current, '%d/%m/%Y'),
            DAYOFWEEK(@current),
            DAYNAME(@current),
            DAY(@current),
            DAYOFYEAR(@current),
            IF(DAYOFWEEK(@current) IN (1,7), 'Weekend', 'Weekday'),
            WEEK(@current, 3),
            MONTHNAME(@current),
            MONTH(@current),
            IF(LAST_DAY(@current) = @current, 'Y', 'N'),
            QUARTER(@current),
            YEAR(@current),
            DATE_FORMAT(@current, '%Y-%m'),
            CONCAT(YEAR(@current), 'Q', QUARTER(@current)),
            (MONTH(@current) + 9) % 12 + 1,
            QUARTER(DATE_ADD(@current, INTERVAL 9 MONTH)),
            IF(MONTH(@current) >= 4, YEAR(@current), YEAR(@current) - 1),
            CONCAT(IF(MONTH(@current) >= 4, YEAR(@current), YEAR(@current) - 1), '-', LPAD((MONTH(@current) + 9) % 12 + 1, 2, '0')),
            CONCAT(IF(MONTH(@current) >= 4, YEAR(@current), YEAR(@current) - 1), 'Q', QUARTER(DATE_ADD(@current, INTERVAL 9 MONTH)))
        );

        SET @current := DATE_ADD(@current, INTERVAL 1 DAY);
    END WHILE;
END//
DELIMITER ;

-- Dumping structure for function havmor.getfreeofcost
DELIMITER //
CREATE FUNCTION `getfreeofcost`(`parpaymenttransactionid` INT) RETURNS decimal(18,2)
    NO SQL
BEGIN
	
	declare amount decimal(18,2);
	
	set amount=(select ifnull(pm.orderamount,0.00)
	from paymenttransactionmaster ptm
	join paymenttype pt on ptm.paymodeid=pt.paymentid and ptm.isdeleted=0 and pt.isdeleted=0
	join paymentmaster pm on ptm.paymentid=pm.paymentid and pm.isdeleted=0
	and ptm.paymenttransactionid=parpaymenttransactionid);
	
	return amount;
	
END//
DELIMITER ;

-- Dumping structure for procedure havmor.gstsummary
DELIMITER //
CREATE PROCEDURE `gstsummary`(IN `orderid` INT)
BEGIN


SET @sql = NULL;
SELECT
  GROUP_CONCAT(DISTINCT
    CONCAT('sum(IF(tm.taxname = ''',
      taxname,
      ''', opt.taxamount, NULL)) AS ',
      replace(taxname, ' ', '')
    )
  ) INTO @sql
from taxmaster tm inner join orderproducttaxdetails opt  on
opt.taxid=tm.taxid and opt.orderid=orderid;


SET @sql = CONCAT('SELECT concat(round(tpm.taxpercentage,2)," %") as `Tax`, ', @sql, ' from orderproducttaxdetails opt\r\ninner join taxmaster tm\r\n  on tm.taxid = opt.taxid and orderid=',orderid,' and opt.isdeleted=0 join orderproductdetails opd on opd.orderproductid=opt.orderproductid join taxprofilemaster tpm on tpm.taxprofileid=opd.taxprofileid group by tpm.taxprofileid');


if (@sql!='') then
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;
else
 select 0;
end if;


END//
DELIMITER ;

