-- Dumping structure for procedure havmor.resetinvnum
DELIMITER //
CREATE PROCEDURE `resetinvnum`()
BEGIN
DECLARE c INT;
DECLARE totalbills INT;

CREATE TEMPORARY TABLE tempordermst
SELECT  @a:=@a+1 srno,orderid FROM ordermaster ,(SELECT @a:= 0) AS a where datekey>=20210401;

set totalbills = (select count(*) from tempordermst);

SET c = 1;
WHILE c <= totalbills DO 

set @orderid=(select ifnull(orderid,0) from tempordermst where srno=c);
update ordermaster set billno=concat('INV',c),modifieddate=now(),issync=0 where orderid=@orderid;

SET c=c+1; 

END WHILE;
drop temporary table tempordermst;
END//
DELIMITER ;

