-- Dumping structure for procedure havmor.salessummary
DELIMITER //
CREATE PROCEDURE `salessummary`(IN `fromdatekey` INT, IN `todatekey` INT, IN `locationid` INT)
BEGIN

SET @sql = NULL;
SELECT
 GROUP_CONCAT(DISTINCT
    CONCAT('sum(IF(opt.taxpercentage = ''',
      opt.taxpercentage,
      ''' and tm.taxname=''',tm.taxname,''' , round(opt.taxamount,2), 0)) AS ',
      '"',concat(taxname,round(opt.taxpercentage,2),'%'),'"'
    ) order by opt.taxpercentage asc
  ) INTO @sql
from ordermaster om inner join orderproducttaxdetails opt on om.orderid=opt.
orderid and om.isdeleted=0 and om.status=1 and opt.isdeleted=0 inner join taxmaster tm 
on tm.taxid=opt.taxid and tm.isdeleted=0  
and om.locationid=locationid and om.datekey between fromdatekey and todatekey
 order by opt.taxpercentage desc;
 
create temporary table orderdata
select om.datekey,STR_TO_DATE(om.datekey,"%Y%m%d") as date,count(om.orderid) totalbills,
round(sum(om.amount),2) amount,round(sum(om.discountamount),2) discount,
round(sum(roundoff),2) roundoff,round(sum(om.taxableamount),2) taxableamount,
round(sum(om.totaltaxamount),2) totaltaxamount,round(sum(grandtotal),2) grandtotal 
from ordermaster om where om.isdeleted=0 and om.status=1 and om.datekey between fromdatekey and todatekey
and om.locationid=locationid group by om.datekey;

create temporary table orderproducts
select  om.datekey,sum(opd.quantity) products from ordermaster om 
join orderproductdetails opd on opd.orderid=om.orderid and opd.isdeleted=0 
and  om.isdeleted=0 and om.status=1 and om.datekey between fromdatekey and todatekey
and om.locationid=locationid group by om.datekey;
 
 
set @sql = concat('select date_format(od.date,"%d %b %Y") date, od.totalbills,op.products, od.amount,
 od.discount, od.taxableamount,', @sql ,', od.totaltaxamount, od.roundoff, od.grandtotal 
from ordermaster om 
inner join orderproducttaxdetails opt 
on opt.orderid=om.orderid and om.isdeleted=0 and opt.isdeleted=0 
inner join taxmaster tm on tm.taxid=opt.taxid and tm.isdeleted=0
inner join orderdata od on od.datekey=om.datekey
inner join orderproducts op on op.datekey=om.datekey
 and om.datekey between "',fromdatekey ,'" and  
 "',todatekey,'" and om.locationid="',locationid,'" and om.status=1 group by om.datekey');
 
if (@sql!='') then
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;
end if;

drop temporary table orderdata;
drop temporary table orderproducts;
END//
DELIMITER ;

